// --- Helper funcs ---

func ticketColor(count int64) string {
	if count > 5 {
		return "red"
	}
	if count > 0 {
		return "amber"
	}
	return "lime"
}

func invoiceColor(count int64) string {
	if count > 0 {
		return "red"
	}
	return "lime"
}

func sumCounts(items []StatusCount) int64 {
	var total int64
	for _, i := range items {
		total += i.Count
	}
	return total
}

func barHeight(value, max, maxH float64) float64 {
	if max == 0 {
		return 0
	}
	h := (value / max) * maxH
	if h > 0 && h < 4 {
		h = 4 // minimum visible bar
	}
	return h
}

func barFill(value float64) string {
	if value > 0 {
		return "#f59e0b" // amber
	}
	return "#3d3d3d" // neutral-700
}

func allZero(months []MonthRevenue) bool {
	for _, m := range months {
		if m.Total > 0 {
			return false
		}
	}
	return true
}

func truncate(s string, n int) string {
	if len(s) <= n {
		return s
	}
	return s[:n] + "…"
}

